from __future__ import annotations

# AUTO-GENERATED MATCHER SHIM (REQ-003-007)
# Matcher: ^(Write|Edit)$
# Generated by build/scripts/generate_hooks.py (REQ-003-007).
# DO NOT EDIT BY HAND - regenerated on every build. Apply NO-REGEN
# sentinel ("# NO-REGEN" or sidecar .noregen) to opt out.
import os as _os
import sys as _sys
import io as _io
import json as _json
import re as _re
import fnmatch as _fnmatch

_MATCHER = '^(Write|Edit)$'

# Cap stdin read so a malicious or buggy upstream cannot OOM the shim
# (CWE-400). Mirrors push_guard_base.MAX_STDIN_BYTES (1 MiB) with a
# small headroom; real Claude/Copilot tool_input commands are well
# below this limit. The cap belongs at the SHIM layer because the
# shim reads stdin BEFORE delegating to the wrapped script. Without
# it, the wrapped script's own cap is applied too late: the OOM has
# already happened.
_SHIM_MAX_STDIN_BYTES = 2 * 1024 * 1024


def _shim_classify(pattern):
    # MIRROR: classify_matcher (build-time, build/scripts/generate_hooks.py)
    # and _shim_classify (runtime, this inlined copy) MUST agree on the
    # grammar. Update both when the grammar changes.
    if pattern.startswith("^") and pattern.endswith("$"):
        return "regex", {"pattern": pattern}
    m = _re.match(r"^([A-Za-z_][A-Za-z0-9_]*)\((.*)\)$", pattern)
    if m:
        return "tool-glob", {"toolName": m.group(1), "argsGlob": m.group(2)}
    return "bare", {"toolName": pattern}


def _shim_normalize_args(tool_args):
    r"""Stringify and whitespace-normalize tool_input for fnmatch comparison.

    REQ-003-007: collapse \s+ to a single space and strip ends. Pattern
    is NOT normalized; authors write patterns assuming single spaces.
    """
    if isinstance(tool_args, dict):
        # Bash hooks place command under "command"; keep this fallback
        # path narrow but correct for the live corpus.
        cmd = tool_args.get("command")
        if isinstance(cmd, str):
            text = cmd
        else:
            text = _json.dumps(tool_args, sort_keys=True)
    elif isinstance(tool_args, str):
        text = tool_args
    elif tool_args is None:
        text = ""
    else:
        text = str(tool_args)
    return _re.sub(r"\s+", " ", text).strip()


def _shim_glob_match(args_glob, tool_args_norm):
    """Match args_glob against tool_args_norm with `|` as alternation.

    fnmatch treats `|` as a literal. Authors expect Claude semantics
    where each `|` branch is a separate glob alternation. Split on
    top-level `|` and OR-fold the results.
    """
    branches = args_glob.split("|") if args_glob else [""]
    for branch in branches:
        if _fnmatch.fnmatchcase(tool_args_norm, branch):
            return True
    return False


def _shim_should_fire(payload):
    kind, params = _shim_classify(_MATCHER)
    # Support both VS Code-compatible snake_case (PascalCase event names)
    # and native camelCase (camelCase event names) payloads.
    # Copilot CLI sends snake_case when the event key is PascalCase,
    # camelCase when the event key is camelCase. See issue #2290.
    tool_name = payload.get("tool_name")
    if tool_name is None:
        tool_name = payload.get("toolName")
    if not isinstance(tool_name, str):
        raise ValueError("hook input missing string `tool_name`/`toolName` field")
    if kind == "regex":
        return _re.fullmatch(params["pattern"], tool_name) is not None
    if kind == "tool-glob":
        if tool_name != params["toolName"]:
            return False
        tool_args = payload.get("tool_input")
        if tool_args is None:
            tool_args = payload.get("toolArgs")
        # camelCase payloads send toolArgs as a JSON string, not a parsed
        # object. Parse it so _shim_normalize_args can extract "command".
        if isinstance(tool_args, str):
            try:
                tool_args = _json.loads(tool_args)
            except ValueError as exc:
                # Host sent a string that is not valid JSON. Log so
                # the operator can diagnose; fall through to normalize
                # which treats raw strings as-is (glob may not match).
                print(
                    "matcher-shim [{}]: toolArgs is not valid JSON: {}".format(
                        _MATCHER, exc
                    ),
                    file=_sys.stderr,
                )
        norm_args = _shim_normalize_args(tool_args)
        return _shim_glob_match(params["argsGlob"], norm_args)
    # bare
    return tool_name == params["toolName"]


def _shim_replay_bytes(payload, raw):
    replay = dict(payload)
    changed = False
    tool_name = replay.get("tool_name")
    if tool_name is None and isinstance(replay.get("toolName"), str):
        replay["tool_name"] = replay["toolName"]
        changed = True
    tool_input = replay.get("tool_input")
    if tool_input is None and "toolArgs" in replay:
        tool_args = replay.get("toolArgs")
        if isinstance(tool_args, str):
            try:
                tool_args = _json.loads(tool_args)
            except ValueError:
                pass
        replay["tool_input"] = tool_args
        changed = True
    if not changed:
        return raw
    return _json.dumps(replay, separators=(",", ":")).encode("utf-8")


def _shim_dispatch():
    try:
        _raw = _sys.stdin.buffer.read(_SHIM_MAX_STDIN_BYTES + 1)
    except Exception as exc:  # pragma: no cover - defensive
        print(
            "matcher-shim [{}]: failed to buffer stdin: {}".format(_MATCHER, exc),
            file=_sys.stderr,
        )
        _sys.exit(2)
    if len(_raw) > _SHIM_MAX_STDIN_BYTES:
        print(
            "matcher-shim [{}]: stdin exceeds {} bytes; refusing".format(
                _MATCHER, _SHIM_MAX_STDIN_BYTES
            ),
            file=_sys.stderr,
        )
        _sys.exit(2)
    try:
        payload = _json.loads(_raw or b"{}")
    except _json.JSONDecodeError as exc:
        print(
            "matcher-shim [{}]: malformed JSON on stdin: {}".format(_MATCHER, exc),
            file=_sys.stderr,
        )
        _sys.exit(2)
    try:
        fire = _shim_should_fire(payload)
    except Exception as exc:
        print(
            "matcher-shim [{}]: dispatch error: {}".format(_MATCHER, exc),
            file=_sys.stderr,
        )
        _sys.exit(2)
    if _os.environ.get("COPILOT_HOOK_DEBUG"):
        kind, _ = _shim_classify(_MATCHER)
        _sys.stderr.write(
            "matcher-shim [{}]: kind={} fired={}\n".format(_MATCHER, kind, fire)
        )
    if not fire:
        _sys.exit(0)
    # Replay a canonical payload into a fresh stdin so wrapped hooks enforce
    # the same schema even when the host sent the camelCase variant.
    _replay = _shim_replay_bytes(payload, _raw)
    _sys.stdin = _io.TextIOWrapper(_io.BytesIO(_replay), encoding="utf-8")
    rc = _original_main(_replay)
    if rc is None:
        rc = 0
    _sys.exit(int(rc))


# END MATCHER SHIM

def _original_main(stdin_bytes):
    # original script body begins below
    #!/usr/bin/env python3
    """Persist plan/TODO state after Write/Edit operations.

    Claude Code PostToolUse hook that saves lightweight checkpoints when
    session logs or plan/TODO files are written. This provides compaction-resume
    context without duplicating full file content.

    Addresses continuation reset after context compaction where plan position
    and TODO status are lost.

    Triggers on:
    - Session log writes (.agents/sessions/*.json)
    - Plan/TODO file writes (TODO.md, PLAN.md, .agents/plan*.md)

    Hook Type: PostToolUse (non-blocking, fail-open)
    Exit Codes:
        0 = Always (never blocks tool use)

    References:
        - Issue #1703 (lifecycle hook infrastructure)
        - Issue #1691 (anti-drift protocol)
        - ADR-008 (protocol automation)
    """


    import json
    import os
    import re
    import sys
    from datetime import UTC, datetime
    from pathlib import Path

    # --- Standard hook boilerplate ---
    _plugin_root = os.environ.get("CLAUDE_PLUGIN_ROOT")
    if _plugin_root:
        _lib_dir = os.path.join(_plugin_root, "lib")
    else:
        _lib_dir = str(Path(__file__).resolve().parents[2] / "lib")
    if os.path.isdir(_lib_dir) and _lib_dir not in sys.path:
        sys.path.insert(0, _lib_dir)

    try:
        from hook_utilities import get_project_directory
        from hook_utilities.guards import skip_if_consumer_repo
    except ImportError:

        def get_project_directory() -> str:
            env_dir = os.environ.get("CLAUDE_PROJECT_DIR", "").strip()
            if env_dir:
                return str(Path(env_dir).resolve())
            return str(Path.cwd())

        def skip_if_consumer_repo(hook_name: str) -> bool:
            agents_path = Path(get_project_directory()) / ".agents"
            if not agents_path.is_dir():
                print(f"[SKIP] {hook_name}: .agents/ not found (consumer repo)", file=sys.stderr)
                return True
            return False


    HOOK_NAME = "plan-state-sync"

    # Patterns for files we want to checkpoint
    # All patterns use (?:^|/) anchors to ensure we match only project-relative
    # paths starting with .agents/, not arbitrary paths containing that substring
    # (e.g., "mock.agents/sessions/log.json" should not match).
    SESSION_LOG_PATTERN = re.compile(r"(?:^|/)\.agents/sessions/.*\.json$")
    PLAN_FILE_PATTERNS = [
        re.compile(r"(?:^|/)TODO\.md$", re.IGNORECASE),
        re.compile(r"(?:^|/)PLAN\.md$", re.IGNORECASE),
        # Match `.agents/plan*.md` at the .agents/ root only. Earlier pattern
        # `\.agents/plan.*\.md$` also matched `.agents/planning/.../*.md` and
        # other nested files, triggering checkpoints for unrelated planning
        # docs. `[^/]*` keeps the match scoped to a single path segment.
        re.compile(r"(?:^|/)\.agents/plan[^/]*\.md$", re.IGNORECASE),
        re.compile(r"(?:^|/)PROJECT-PLAN\.md$", re.IGNORECASE),
    ]

    SUMMARY_MAX_CHARS = 500


    def _read_stdin_json() -> dict | None:
        """Read and parse JSON from stdin (Claude hook input)."""
        if sys.stdin.isatty():
            return None
        try:
            data = sys.stdin.read().strip()
            if not data:
                return None
            return json.loads(data)
        except (json.JSONDecodeError, OSError):
            return None


    def _extract_file_path(hook_input: dict) -> str | None:
        """Extract the file path from hook input.

        Defends against malformed hook input where ``hook_input`` or
        ``tool_input`` is not a mapping, and against non-string ``file_path``
        values that would later break string ops in ``_is_checkpointable_file``.
        Returning ``None`` lets the caller skip checkpointing without
        disabling the hook silently.
        """
        if not isinstance(hook_input, dict):
            return None
        tool_input = hook_input.get("tool_input", {})
        if not isinstance(tool_input, dict):
            return None
        # Write tool uses 'file_path', Edit tool may use 'file_path' or 'path'.
        # Require a non-empty string; ignore other types so downstream code
        # never operates on, e.g., a dict or None.
        for key in ("file_path", "path"):
            value = tool_input.get(key)
            if isinstance(value, str):
                stripped = value.strip()
                if stripped:
                    return stripped
        return None


    def _is_checkpointable_file(file_path: str) -> bool:
        """Check if the written file should trigger a checkpoint."""
        # Normalize path separators
        normalized = file_path.replace("\\", "/")

        if SESSION_LOG_PATTERN.search(normalized):
            return True

        for pattern in PLAN_FILE_PATTERNS:
            if pattern.search(normalized):
                return True

        return False


    def _read_file_summary(file_path: str) -> str:
        """Read first SUMMARY_MAX_CHARS of a file as a summary.

        Streams only the bytes needed instead of loading the whole file, so
        large session logs do not balloon hook memory.
        """
        try:
            path = Path(file_path)
            if not path.exists():
                return "(file not found)"
            with path.open(encoding="utf-8", errors="replace") as handle:
                content = handle.read(SUMMARY_MAX_CHARS + 1)
            if len(content) > SUMMARY_MAX_CHARS:
                return content[:SUMMARY_MAX_CHARS] + "..."
            return content
        except OSError:
            return "(read error)"


    def _acquire_lock(handle) -> None:
        """Acquire an advisory exclusive lock on an open file handle."""
        if os.name == "nt":  # pragma: no cover - platform branch
            import msvcrt

            msvcrt.locking(handle.fileno(), msvcrt.LK_LOCK, 1)
            return
        import fcntl

        fcntl.flock(handle.fileno(), fcntl.LOCK_EX)


    def _release_lock(handle) -> None:
        """Release the advisory lock held on an open file handle."""
        if os.name == "nt":  # pragma: no cover - platform branch
            import msvcrt

            try:
                msvcrt.locking(handle.fileno(), msvcrt.LK_UNLCK, 1)
            except OSError:
                pass
            return
        import fcntl

        try:
            fcntl.flock(handle.fileno(), fcntl.LOCK_UN)
        except OSError:
            pass


    def _write_checkpoint(project_dir: str, file_path: str, summary: str) -> None:
        """Write a lightweight checkpoint for plan/state recovery.

        Concurrent PostToolUse hooks can race on the per-day checkpoint file, so
        the read-modify-write sequence is wrapped in an advisory exclusive lock
        (fcntl.flock on POSIX, msvcrt.locking on Windows). Without the lock,
        interleaved writes drop entries or produce invalid JSON.
        """
        checkpoint_dir = Path(project_dir) / ".agents" / ".hook-state"
        checkpoint_dir.mkdir(parents=True, exist_ok=True)

        today = datetime.now(tz=UTC).strftime("%Y-%m-%d")
        timestamp = datetime.now(tz=UTC).isoformat()

        checkpoint_file = checkpoint_dir / f"plan-checkpoint-{today}.json"

        # Open r+ when present, w+ to create; serialize via OS advisory lock.
        mode = "r+" if checkpoint_file.exists() else "w+"
        with checkpoint_file.open(mode, encoding="utf-8") as handle:
            _acquire_lock(handle)
            try:
                checkpoints: list[dict] = []
                handle.seek(0)
                raw = handle.read()
                if raw:
                    try:
                        existing = json.loads(raw)
                        if isinstance(existing, list):
                            checkpoints = existing
                    except json.JSONDecodeError:
                        # Preserve the corrupt file under .corrupt so prior
                        # checkpoints are not silently wiped when the daily
                        # JSON cannot be parsed. The new write proceeds with
                        # an empty list so the hook still records progress.
                        corrupt_path = checkpoint_file.with_suffix(
                            checkpoint_file.suffix + ".corrupt"
                        )
                        try:
                            corrupt_path.write_text(raw, encoding="utf-8")
                        except OSError:
                            pass

                checkpoints.append({
                    "file": file_path,
                    "timestamp": timestamp,
                    "summary": summary,
                })

                # Keep only last 20 checkpoints to avoid unbounded growth
                if len(checkpoints) > 20:
                    checkpoints = checkpoints[-20:]

                handle.seek(0)
                handle.truncate()
                handle.write(
                    json.dumps(checkpoints, indent=2, ensure_ascii=False)
                )
                handle.flush()
            finally:
                _release_lock(handle)


    def main() -> None:
        """Checkpoint plan/TODO state after relevant file writes."""
        # Read stdin first to ensure it's drained before any early exit,
        # maintaining the fail-open drain contract with the harness.
        hook_input = _read_stdin_json()

        if skip_if_consumer_repo(HOOK_NAME):
            sys.exit(0)

        if hook_input is None:
            sys.exit(0)

        file_path = _extract_file_path(hook_input)
        if not file_path:
            sys.exit(0)

        if not _is_checkpointable_file(file_path):
            sys.exit(0)

        project_dir = get_project_directory()
        project_root = Path(project_dir).resolve()

        # Anchor relative paths to the project root so a hook process whose
        # CWD is a subdirectory still resolves to the file Claude wrote, and
        # reject paths that escape the repo (CWE-22 path traversal).
        candidate = Path(file_path)
        resolved = (
            candidate.resolve()
            if candidate.is_absolute()
            else (project_root / candidate).resolve()
        )
        try:
            resolved.relative_to(project_root)
        except ValueError:
            print(
                f"[WARNING] {HOOK_NAME}: ignoring out-of-root path: {file_path}",
                file=sys.stderr,
            )
            sys.exit(0)

        summary = _read_file_summary(str(resolved))

        # Persist a project-relative path so checkpoints stay portable across
        # machines and CWDs, instead of leaking absolute paths from whoever
        # invoked Claude.
        try:
            recorded_path = str(resolved.relative_to(project_root))
        except ValueError:
            recorded_path = file_path

        _write_checkpoint(project_dir, recorded_path, summary)

        print(f"[INFO] {HOOK_NAME}: Checkpointed state for {recorded_path}", file=sys.stderr)
    try:
        return main()
    except Exception as _exc:
        sys.stderr.write('[WARNING] hook error (fail-open): ' + str(_exc) + '\n')
        return 0

_shim_dispatch()
